#!/usr/bin/env bash
# Purpose:
#   Build and run the M1 CFSM unit test binary. This validates the
#   FragmentationStateTable behavior without touching the ZNS device.
#
# Typical usage:
#   experiments/M1/run_unit_tests.sh
set -euo pipefail

SCRIPT_DIR="$(cd -- "$(dirname -- "${BASH_SOURCE[0]}")" && pwd)"
RESULT_PURPOSE="${RESULT_PURPOSE:-unit-tests-v1}"
source "${SCRIPT_DIR}/common.sh"

# Store the exact configuration beside the test log for reproducibility.
mkdir -p "${RESULT_DIR}"
print_config | tee "${RESULT_DIR}/unit_test_config.txt"

# The test target is generated by the ZenFS plugin CMakeLists.
cmake --build "${BUILD_DEBUG_DIR}" --target frag_state_table_test -j"$(nproc)"

# CMake may place the binary at the build root or under a plugin subdirectory,
# so find it instead of hardcoding a path.
TEST_BIN="$(find "${BUILD_DEBUG_DIR}" -name 'frag_state_table_test' -type f | head -n 1)"
if [[ -z "${TEST_BIN}" ]]; then
  echo "frag_state_table_test was not found under ${BUILD_DEBUG_DIR}" >&2
  exit 1
fi

# Preserve the gtest output as the primary M1 correctness evidence.
"${TEST_BIN}" | tee "${RESULT_DIR}/frag_state_table_test.log"
